   641→/**
   642→ * Complete student insights for parent dashboard.
   643→ * Aggregated from all Maestro interactions.
   644→ */
   645→export interface StudentInsights {
   646→  studentId: string;
   647→  studentName: string;
   648→  lastUpdated: Date;
   649→  strengths: MaestroObservation[];
   650→  growthAreas: MaestroObservation[];
   651→  strategies: LearningStrategy[];
   652→  learningStyle: LearningStyleProfile;
   653→  totalSessions: number;
   654→  totalMinutes: number;
   655→  maestriInteracted: string[];
   656→}
   657→
   658→// === AMBIENT AUDIO TYPES ===
   659→
   660→/**
   661→ * Audio focus modes for procedural generation and ambient sounds.
   662→ */
   663→export type AudioMode =
   664→  | 'white_noise'
   665→  | 'pink_noise'
   666→  | 'brown_noise'
   667→  | 'binaural_alpha'    // 8-14 Hz - Relaxed focus
   668→  | 'binaural_beta'     // 14-30 Hz - Active concentration
   669→  | 'binaural_theta'    // 4-8 Hz - Creative, meditative
   670→  | 'rain'
   671→  | 'thunderstorm'
   672→  | 'fireplace'
   673→  | 'cafe'
   674→  | 'library'
   675→  | 'forest'
   676→  | 'ocean'
   677→  | 'night';
   678→
   679→/**
   680→ * Preset combinations of audio modes.
   681→ */
   682→export type AudioPreset =
   683→  | 'deep_work'        // Binaural beta + brown noise
   684→  | 'library'          // Quiet ambience + white noise
   685→  | 'starbucks'        // Café + soft lo-fi
   686→  | 'rainy_day'        // Rain + fireplace + thunder
   687→  | 'nature'           // Forest + birds + wind
   688→  | 'focus'            // Binaural alpha
   689→  | 'creative';        // Binaural theta + nature
   690→
   691→/**
   692→ * Playback state of ambient audio system.
   693→ */
   694→export type AudioPlaybackState = 'idle' | 'playing' | 'paused' | 'loading' | 'error';
   695→
   696→/**
   697→ * Configuration for a single audio layer in the mixer.
   698→ */
   699→export interface AudioLayer {
   700→  id: string;
   701→  mode: AudioMode;
   702→  volume: number;      // 0-1
   703→  enabled: boolean;
   704→}
   705→
   706→/**
   707→ * Ambient audio system state.
   708→ */
   709→export interface AmbientAudioState {
   710→  playbackState: AudioPlaybackState;
   711→  masterVolume: number;        // 0-1
   712→  currentPreset: AudioPreset | null;
   713→  layers: AudioLayer[];
