     1→// ============================================================================
     2→// SUMMARY HANDLER
     3→// Creates structured summaries with sections and key points
     4→// ============================================================================
     5→
     6→import { registerToolHandler } from '../tool-executor';
     7→import { nanoid } from 'nanoid';
     8→import type { SummaryData, SummarySection, ToolExecutionResult } from '@/types/tools';
     9→import { createEmptyStudentSummary } from '@/types/tools';
    10→
    11→/**
    12→ * Validate summary sections structure
    13→ */
    14→function validateSections(
    15→  sections: unknown[]
    16→): { valid: boolean; error?: string } {
    17→  if (!sections || sections.length === 0) {
    18→    return { valid: false, error: 'At least one section is required' };
    19→  }
    20→
    21→  for (let i = 0; i < sections.length; i++) {
    22→    const s = sections[i] as Partial<SummarySection>;
    23→
    24→    if (!s.title || typeof s.title !== 'string') {
    25→      return {
    26→        valid: false,
    27→        error: `Section ${i + 1}: title is required`,
    28→      };
    29→    }
    30→
    31→    if (!s.content || typeof s.content !== 'string') {
    32→      return {
    33→        valid: false,
    34→        error: `Section ${i + 1}: content is required`,
    35→      };
    36→    }
    37→
    38→    if (s.keyPoints && !Array.isArray(s.keyPoints)) {
    39→      return {
    40→        valid: false,
    41→        error: `Section ${i + 1}: keyPoints must be an array`,
    42→      };
    43→    }
    44→  }
    45→
    46→  return { valid: true };
    47→}
    48→
    49→/**
    50→ * Register the summary handler
    51→ */
    52→registerToolHandler('create_summary', async (args): Promise<ToolExecutionResult> => {
    53→  const { topic, sections, length } = args as {
    54→    topic: string;
    55→    sections: Array<{
    56→      title: string;
    57→      content: string;
    58→      keyPoints?: string[];
    59→    }>;
    60→    length?: 'short' | 'medium' | 'long';
    61→  };
    62→
    63→  // Validate topic
    64→  if (!topic || typeof topic !== 'string') {
    65→    return {
    66→      success: false,
    67→      toolId: nanoid(),
    68→      toolType: 'summary',
    69→      error: 'Topic is required and must be a string',
    70→    };
    71→  }
    72→
    73→  // Validate sections
    74→  const validation = validateSections(sections);
    75→  if (!validation.valid) {
    76→    return {
    77→      success: false,
    78→      toolId: nanoid(),
    79→      toolType: 'summary',
    80→      error: validation.error,
    81→    };
    82→  }
    83→
    84→  // Normalize sections structure
    85→  const normalizedSections: SummarySection[] = sections.map((s) => ({
    86→    title: s.title.trim(),
    87→    content: s.content.trim(),
    88→    keyPoints: s.keyPoints?.map((p) => p.trim()),
    89→  }));
    90→
    91→  const data: SummaryData = {
    92→    topic: topic.trim(),
    93→    sections: normalizedSections,
    94→    length,
    95→  };
    96→
    97→  return {
    98→    success: true,
    99→    toolId: nanoid(),
   100→    toolType: 'summary',
   101→    data,
   102→  };
   103→});
   104→
   105→/**
   106→ * Handler for opening the student summary editor (maieutic method)
   107→ * Student writes their own summary with guidance
   108→ */
   109→registerToolHandler('open_student_summary', async (args, context): Promise<ToolExecutionResult> => {
   110→  const { topic } = args as { topic: string };
   111→
   112→  if (!topic || typeof topic !== 'string') {
   113→    return {
   114→      success: false,
   115→      toolId: nanoid(),
   116→      toolType: 'summary',
   117→      error: 'Topic is required',
   118→    };
   119→  }
   120→
   121→  // Create empty student summary structure
   122→  const studentSummary = createEmptyStudentSummary(
   123→    topic.trim(),
   124→    context?.maestroId,
   125→    context?.sessionId
   126→  );
   127→
   128→  return {
   129→    success: true,
   130→    toolId: studentSummary.id,
   131→    toolType: 'summary',
   132→    data: {
   133→      type: 'student_summary',
   134→      ...studentSummary,
   135→    },
   136→  };
   137→});
   138→
   139→/**
   140→ * Handler for adding inline comments to student summary
   141→ */
   142→registerToolHandler('student_summary_add_comment', async (args, context): Promise<ToolExecutionResult> => {
   143→  const { sectionId, startOffset, endOffset, text } = args as {
   144→    sectionId: string;
   145→    startOffset: number;
   146→    endOffset: number;
   147→    text: string;
   148→  };
   149→
   150→  if (!sectionId || !text) {
   151→    return {
   152→      success: false,
   153→      toolId: nanoid(),
   154→      toolType: 'summary',
   155→      error: 'sectionId and text are required',
   156→    };
   157→  }
   158→
   159→  // This emits an SSE event to update the client
   160→  return {
   161→    success: true,
   162→    toolId: nanoid(),
   163→    toolType: 'summary',
   164→    data: {
   165→      type: 'student_summary_comment',
   166→      sectionId,
   167→      startOffset,
   168→      endOffset,
   169→      text,
   170→      maestroId: context?.maestroId,
   171→    },
   172→  };
   173→});
   174→
   175→export { validateSections };
   176→

