     1→// ============================================================================
     2→// DEMO HANDLER
     3→// Creates HTML/JS interactive simulations
     4→// Security: Validates code before execution
     5→// ============================================================================
     6→
     7→import { registerToolHandler } from '../tool-executor';
     8→import { nanoid } from 'nanoid';
     9→import type { DemoData, ToolExecutionResult } from '@/types/tools';
    10→
    11→/**
    12→ * Dangerous patterns to block in JavaScript code
    13→ * Safety: Prevents data exfiltration and malicious actions
    14→ */
    15→const DANGEROUS_JS_PATTERNS: Array<{ pattern: RegExp; description: string }> = [
    16→  { pattern: /document\.cookie/i, description: 'Cookie access' },
    17→  { pattern: /localStorage/i, description: 'LocalStorage access' },
    18→  { pattern: /sessionStorage/i, description: 'SessionStorage access' },
    19→  { pattern: /indexedDB/i, description: 'IndexedDB access' },
    20→  { pattern: /fetch\s*\(/i, description: 'Network fetch' },
    21→  { pattern: /XMLHttpRequest/i, description: 'XHR request' },
    22→  { pattern: /window\.open/i, description: 'Window open' },
    23→  { pattern: /window\.location/i, description: 'Location manipulation' },
    24→  { pattern: /eval\s*\(/i, description: 'Eval execution' },
    25→  { pattern: /Function\s*\(/i, description: 'Function constructor' },
    26→  { pattern: /new\s+Function/i, description: 'Function constructor' },
    27→  { pattern: /import\s*\(/i, description: 'Dynamic import' },
    28→  { pattern: /require\s*\(/i, description: 'CommonJS require' },
    29→  { pattern: /postMessage/i, description: 'Cross-origin messaging' },
    30→  { pattern: /navigator\.(geolocation|clipboard|mediaDevices)/i, description: 'Sensitive API access' },
    31→];
    32→
    33→/**
    34→ * Validate code for dangerous patterns
    35→ */
    36→function validateCode(code: string): { safe: boolean; violations: string[] } {
    37→  const violations: string[] = [];
    38→
    39→  for (const { pattern, description } of DANGEROUS_JS_PATTERNS) {
    40→    if (pattern.test(code)) {
    41→      violations.push(description);
    42→    }
    43→  }
    44→
    45→  return {
    46→    safe: violations.length === 0,
    47→    violations,
    48→  };
    49→}
    50→
    51→/**
    52→ * Remove script elements using character-by-character state machine
    53→ * This avoids regex-based multi-character bypass vulnerabilities
    54→ */
    55→function removeScriptElements(html: string): string {
    56→  let result = '';
    57→  let i = 0;
    58→  const lowerHtml = html.toLowerCase();
    59→
    60→  while (i < html.length) {
    61→    // Check for opening script tag
    62→    if (lowerHtml.substring(i, i + 7) === '<script') {
    63→      // Find the end of this script element
    64→      const closingTag = lowerHtml.indexOf('</script', i);
    65→      if (closingTag !== -1) {
    66→        // Skip to after the closing tag
    67→        const endOfClosing = lowerHtml.indexOf('>', closingTag);
    68→        i = endOfClosing !== -1 ? endOfClosing + 1 : html.length;
    69→      } else {
    70→        // No closing tag, skip to end
    71→        i = html.length;
    72→      }
    73→    } else {
    74→      result += html[i];
    75→      i++;
    76→    }
    77→  }
    78→
    79→  return result;
    80→}
    81→
    82→/**
    83→ * Sanitize HTML to prevent XSS
    84→ * Note: Multi-layer sanitization, the iframe sandbox provides main security
    85→ */
    86→function sanitizeHtml(html: string): string {
    87→  // First pass: remove script elements entirely (state machine approach)
    88→  let sanitized = removeScriptElements(html);
    89→
    90→  // Remove event handlers by finding on* attributes
    91→  // Use state machine to properly handle attribute context
    92→  let result = '';
    93→  let inTag = false;
    94→  let i = 0;
    95→
    96→  while (i < sanitized.length) {
    97→    const char = sanitized[i];
    98→
    99→    if (char === '<') {
   100→      inTag = true;
   101→      result += char;
   102→      i++;
   103→    } else if (char === '>') {
   104→      inTag = false;
   105→      result += char;
   106→      i++;
   107→    } else if (inTag && sanitized.substring(i).match(/^on[a-z]+\s*=/i)) {
   108→      // Found event handler, replace with data attribute
   109→      const match = sanitized.substring(i).match(/^on[a-z]+/i);
   110→      if (match) {
   111→        result += 'data-removed-' + match[0].substring(2);
   112→        i += match[0].length;
   113→      }
   114→    } else {
   115→      result += char;
   116→      i++;
   117→    }
   118→  }
   119→
   120→  sanitized = result;
   121→
   122→  // Remove dangerous URL schemes (normalize and check)
   123→  // Decode any HTML entities first
   124→  const decoded = sanitized
   125→    .replace(/&#x([0-9a-f]+);?/gi, (_, hex) => String.fromCharCode(parseInt(hex, 16)))
   126→    .replace(/&#(\d+);?/g, (_, dec) => String.fromCharCode(parseInt(dec, 10)));
   127→
   128→  // Remove dangerous protocols
   129→  sanitized = decoded
   130→    .replace(/javascript\s*:/gi, 'removed:')
   131→    .replace(/vbscript\s*:/gi, 'removed:')
   132→    .replace(/data\s*:/gi, 'removed:');
   133→
   134→  return sanitized;
   135→}
   136→
   137→/**
   138→ * Register the demo handler
   139→ */
   140→registerToolHandler('create_demo', async (args): Promise<ToolExecutionResult> => {
   141→  const { title, description, html, css, js } = args as {
   142→    title: string;
   143→    description?: string;
   144→    html: string;
   145→    css?: string;
   146→    js?: string;
   147→  };
   148→
   149→  // Validate title
   150→  if (!title || typeof title !== 'string') {
   151→    return {
   152→      success: false,
   153→      toolId: nanoid(),
   154→      toolType: 'demo',
   155→      error: 'Title is required and must be a string',
   156→    };
   157→  }
   158→
   159→  // Validate HTML
   160→  if (!html || typeof html !== 'string') {
   161→    return {
   162→      success: false,
   163→      toolId: nanoid(),
   164→      toolType: 'demo',
   165→      error: 'HTML content is required',
   166→    };
   167→  }
   168→
   169→  // Validate JavaScript if provided
   170→  if (js) {
   171→    const jsValidation = validateCode(js);
   172→    if (!jsValidation.safe) {
   173→      return {
   174→        success: false,
   175→        toolId: nanoid(),
   176→        toolType: 'demo',
   177→        error: `JavaScript contains blocked patterns: ${jsValidation.violations.join(', ')}`,
   178→      };
   179→    }
   180→  }
   181→
   182→  // Sanitize HTML
   183→  const sanitizedHtml = sanitizeHtml(html);
   184→
   185→  const data: DemoData = {
   186→    title: title.trim(),
   187→    description: description?.trim(),
