    57→  /** Callback when materials are deleted */
    58→  onDeleteMaterials?: (ids: string[]) => Promise<void>;
    59→  /** Callback when materials are moved */
    60→  onMoveMaterials?: (ids: string[], collectionId: string | null) => Promise<void>;
    61→  /** Callback when collection is created */
    62→  onCreateCollection?: (name: string, parentId?: string | null) => Promise<void>;
    63→  /** Additional CSS classes */
    64→  className?: string;
    65→}
    66→
    67→// ============================================================================
    68→// Constants
