    74→    label: 'Esplora',
    75→    icon: <FolderTree className="w-4 h-4" />,
    76→    description: 'Vista a cartelle con navigazione gerarchica',
    77→  },
    78→  {
    79→    id: 'gallery',
    80→    label: 'Galleria',
    81→    icon: <LayoutGrid className="w-4 h-4" />,
    82→    description: 'Griglia con anteprime grandi',
    83→  },
    84→  {
    85→    id: 'timeline',
    86→    label: 'Timeline',
    87→    icon: <Clock className="w-4 h-4" />,
    88→    description: 'Materiali ordinati cronologicamente',
    89→  },
    90→  {
    91→    id: 'calendar',
    92→    label: 'Calendario',
    93→    icon: <Calendar className="w-4 h-4" />,
    94→    description: 'Vista calendario per data',
    95→  },
    96→];
    97→
    98→// ============================================================================
    99→// Main Component
   100→// ============================================================================
   101→
   102→export function KnowledgeHub({
   103→  materials = [],
   104→  collections: initialCollections = [],
   105→  onOpenMaterial,
   106→  onDeleteMaterials,
   107→  onMoveMaterials,
   108→  onCreateCollection,
   109→  className,
   110→}: KnowledgeHubProps) {
   111→  // View state
   112→  const [viewMode, setViewMode] = useState<ViewMode>('gallery');
   113→  const [isSidebarCollapsed, setIsSidebarCollapsed] = useState(false);
   114→  const [selectedMaterialIds, setSelectedMaterialIds] = useState<Set<string>>(new Set());
   115→  const [expandedFolders, setExpandedFolders] = useState<Set<string>>(new Set());
   116→  const [previewMaterial, setPreviewMaterial] = useState<KnowledgeHubMaterial | null>(null);
   117→
   118→  // Convert KnowledgeHubMaterial to SearchableMaterial for search
   119→  const searchableMaterials = useMemo<SearchableMaterial[]>(() => {
   120→    return materials.map((m) => ({
   121→      id: m.id,
   122→      title: m.title,
   123→      toolType: m.toolType,
   124→      createdAt: m.createdAt instanceof Date ? m.createdAt : new Date(m.createdAt),
   125→    }));
   126→  }, [materials]);
   127→
   128→  // Search hook
   129→  const {
   130→    query: searchQuery,
   131→    setQuery: setSearchQuery,
   132→    results: searchResults,
   133→    isSearching,
   134→    hasSearched,
   135→    clearSearch,
   136→  } = useMaterialsSearch(searchableMaterials);
   137→
   138→  // Collections hook
   139→  const {
   140→    collections: _collections, // Available for future features
   141→    collectionTree,
   142→    selectedCollectionId,
   143→    selectCollection,
   144→    createCollection: _createCollection, // Available for future features
   145→  } = useCollections({
   146→    initialCollections: initialCollections.map((c) => ({
   147→      id: c.id,
   148→      name: c.name,
   149→      icon: c.icon,
   150→      color: c.color,
   151→      parentId: c.parentId,
   152→      materialCount: c.count,
   153→      createdAt: new Date(),
   154→      updatedAt: new Date(),
   155→    })),
   156→    onCreateCollection: async (col) => {
   157→      await onCreateCollection?.(col.name, col.parentId);
   158→    },
   159→    onMoveToCollection: async (ids, colId) => {
   160→      await onMoveMaterials?.(ids, colId);
   161→    },
   162→  });
   163→
   164→  // Filter materials based on search and selection
   165→  const displayedMaterials = useMemo<KnowledgeHubMaterial[]>(() => {
   166→    if (hasSearched && searchResults.length > 0) {
   167→      const searchIds = new Set(searchResults.map((r) => r.item.id));
   168→      return materials.filter((m) => searchIds.has(m.id));
