   306→          )}
   307→        </div>
   308→      </div>
   309→
   310→      {/* Main Content */}
   311→      <div className="flex-1 overflow-hidden flex">
   312→        {/* Sidebar */}
   313→        {!isSidebarCollapsed && viewMode !== 'explorer' && (
   314→          <div className="w-64 flex-shrink-0 bg-white dark:bg-slate-800 border-r border-slate-200 dark:border-slate-700 overflow-y-auto">
   315→            <SidebarNavigation
   316→              collections={collectionTree}
