   341→                  <div className="animate-spin w-8 h-8 border-2 border-primary border-t-transparent rounded-full" />
   342→                </div>
   343→              ) : (
   344→                renderView()
   345→              )}
   346→            </motion.div>
   347→          </AnimatePresence>
   348→        </div>
   349→
   350→        {/* Preview Panel (Task 7.16) */}
   351→        <AnimatePresence>
   352→          {previewMaterial && (
   353→            <motion.div
   354→              initial={{ width: 0, opacity: 0 }}
   355→              animate={{ width: 320, opacity: 1 }}
   356→              exit={{ width: 0, opacity: 0 }}
   357→              className="flex-shrink-0 bg-white dark:bg-slate-800 border-l border-slate-200 dark:border-slate-700 overflow-hidden"
   358→            >
   359→              <div className="p-4 w-80">
   360→                <div className="flex items-center justify-between mb-4">
   361→                  <h3 className="font-semibold text-slate-900 dark:text-white">
   362→                    Anteprima
   363→                  </h3>
   364→                  <Button
   365→                    variant="ghost"
   366→                    size="icon"
   367→                    onClick={() => setPreviewMaterial(null)}
   368→                    aria-label="Chiudi anteprima"
   369→                  >
   370→                    <X className="w-4 h-4" />
   371→                  </Button>
   372→                </div>
   373→                <MaterialCard
   374→                  material={{
   375→                    id: previewMaterial.id,
