   377→                    type: previewMaterial.toolType,
   378→                    createdAt: previewMaterial.createdAt instanceof Date
   379→                      ? previewMaterial.createdAt
   380→                      : new Date(previewMaterial.createdAt),
   381→                    updatedAt: previewMaterial.updatedAt
   382→                      ? (previewMaterial.updatedAt instanceof Date
   383→                          ? previewMaterial.updatedAt
   384→                          : new Date(previewMaterial.updatedAt))
   385→                      : (previewMaterial.createdAt instanceof Date
   386→                          ? previewMaterial.createdAt
   387→                          : new Date(previewMaterial.createdAt)),
   388→                    tags: previewMaterial.tags,
   389→                    isFavorite: previewMaterial.isFavorite,
   390→                  }}
   391→                  onOpen={() => handleSelectMaterial(previewMaterial)}
   392→                />
   393→              </div>
