   395→          )}
   396→        </AnimatePresence>
   397→      </div>
   398→
   399→      {/* Sidebar Toggle */}
   400→      {viewMode !== 'explorer' && (
   401→        <button
   402→          onClick={() => setIsSidebarCollapsed((prev) => !prev)}
