// ============================================================================
// STUDY KIT HANDLER
// Process PDF and generate study materials (summary, mindmap, demo, quiz)
// Wave 2: Auto-generate study kit from PDF upload
// ============================================================================

import * as pdfParse from 'pdf-parse';
import { chatCompletion } from '@/lib/ai/providers';
import { logger } from '@/lib/logger';
import type { MindmapData, QuizData, DemoData } from '@/types/tools';
import type { StudyKit } from '@/types/study-kit';

/**
 * Extract text from PDF buffer using pdf-parse (server-side library)
 */
export async function extractTextFromPDF(buffer: Buffer): Promise<{ text: string; pageCount: number }> {
  try {
    // pdf-parse is a CJS module, need to handle default export
    const parse = (pdfParse as unknown as { default?: typeof pdfParse }).default || pdfParse;
    const data = await (parse as (buffer: Buffer) => Promise<{ text: string; numpages: number }>)(buffer);
    return {
      text: data.text,
      pageCount: data.numpages,
    };
  } catch (error) {
    logger.error('Failed to extract text from PDF', { error });
    throw new Error('Failed to parse PDF');
  }
}

